from flask import Flask, request, jsonifyimport datetimeapp = Flask(__name__)# Örnek öğrenci veritabanıogrenciler = {    "101": {"ad": "Selin", "veli_tel": "555...", "durum": "disarida"}}@app.route('/islem/<ogrenci_id>')def giris_cikis_yap(ogrenci_id):    ogrenci = ogrenciler.get(ogrenci_id)        if not ogrenci:        return "Öğrenci bulunamadı!"    zaman = datetime.datetime.now().strftime('%H:%M')        if ogrenci["durum"] == "disarida":        ogrenci["durum"] = "iceride"        mesaj = f"{ogrenci['ad']} kursa GİRİŞ yaptı. Saat: {zaman}"        # sms_gonder(ogrenci["veli_tel"], mesaj)    else:        ogrenci["durum"] = "disarida"        mesaj = f"{ogrenci['ad']} kurstan ÇIKIŞ yaptı. Saat: {zaman}"        # sms_gonder(ogrenci["veli_tel"], mesaj)    return f"İşlem Başarılı: {mesaj}"if __name__ == '__main__':    app.run(host='0.0.0.0', port=5000)